752	    ['密着クリアランス',  'L2−Lc',       fmt(L2-Lc,3),      'mm',    true],
753	  ];
754	  rows.forEach(row => {
755	    if (row === null) {
756	      const tr = document.createElement('tr');
757	      tr.innerHTML = '<td colspan="4" style="padding:2px;background:#f7f7f7;border-bottom:0.5px solid #e0e0e0"></td>';
