function calc() {
  const matKey = ge('material').value;
  const D      = parseFloat(ge('D').value);
  const L1     = parseFloat(ge('L1').value);
  const stroke = parseFloat(ge('stroke').value);
  const P2req  = parseFloat(ge('P2in').value);
  const mat    = MATERIALS[matKey];
  const G      = mat.G;

  const L2 = L1 - stroke;
  ge('disp-L2').textContent = (!isNaN(L2) && L2 > 0) ? fmt(L2, 2) : '—';
  ge('disp-G').textContent  = G.toLocaleString();

  const alertBox = ge('alert-box');
  alertBox.innerHTML = '';

  // Validate
  const errs = [];
  if (isNaN(D)||D<=0)      errs.push('コイル中心径 D');
  if (isNaN(L1)||L1<=0)    errs.push('セット長 L1');
  if (isNaN(stroke)||stroke<=0) errs.push('ストローク δ');
  if (isNaN(P2req)||P2req<=0)   errs.push('ばね力 P2');
  if (errs.length) {
    alertBox.innerHTML = '<div class="alert al-dn"><b>入力エラー</b> — ' + errs.join('・') + ' を確認してください。</div>';
    drawGoodman(null, null, null); return;
  }
  if (L2 <= 0) {
    alertBox.innerHTML = '<div class="alert al-dn"><b>長さエラー</b> — ストローク δ はセット長 L1 より小さくしてください。</div>';
    drawGoodman(null, null, null); return;
  }

  // k from requirements
  const k_req = P2req / stroke;

  // Find minimum JIS wire diameter satisfying all constraints
  let sol = null;
  for (const d_try of JIS_WIRE_D) {
    const sigmaB = getSigmaB(matKey, d_try);
    const C_try  = D / d_try;
    if (C_try < 3) continue; // コイル径に対して線径が大きすぎ
    const K_try  = (4*C_try-1)/(4*C_try-4) + 0.615/C_try;
    const tau2   = K_try * 8 * P2req * D / (Math.PI * Math.pow(d_try, 3));
    if (tau2 > 0.45 * sigmaB) continue; // 応力超過

    const Na_exact = G * Math.pow(d_try, 4) / (8 * k_req * Math.pow(D, 3));
    const Na_use   = Math.max(3, Math.ceil(Na_exact * 2) / 2); // 0.5巻単位切上げ、最小3
    const k_act    = G * Math.pow(d_try, 4) / (8 * Na_use * Math.pow(D, 3));
    const Hf_try   = L2 + P2req / k_act;
    const Lc_try   = (Na_use + 2) * d_try;

    if (Lc_try >= L2) continue; // 密着高さ ≥ 作動時長さ
    if (Hf_try <= L1) continue; // 自由高さ ≤ セット長

    sol = { d: d_try, Na: Na_use, k: k_act, Hf: Hf_try, Lc: Lc_try,
            C: C_try, K: K_try, sigmaB };
    break;
  }

  if (!sol) {
    alertBox.innerHTML = '<div class="alert al-dn"><b>解なし</b> — 条件を満たす JIS 標準線径が見つかりません。D を大きくするか、P2・ストロークを見直してください。</div>';
    drawGoodman(null, null, null); return;
  }

  const { d, Na, k, Hf, Lc, C, K, sigmaB } = sol;

  // All stress / load values
  const d1       = Hf - L1;
  const P1       = k * d1;
  const d2       = Hf - L2;
  const P2       = k * d2;
  const d_solid  = Hf - Lc;
  const P_solid  = k * d_solid;
  const tau1     = K * 8 * P1 * D / (Math.PI * Math.pow(d, 3));
  const tau2     = K * 8 * P2 * D / (Math.PI * Math.pow(d, 3));
  const tau_sol  = K * 8 * P_solid * D / (Math.PI * Math.pow(d, 3));
  const x1       = tau1 / sigmaB;
  const y1       = tau2 / sigmaB;
  const y_sol    = tau_sol / sigmaB;
  const R        = P1 / P2;
  const solidOK  = Lc < L2;
  const stressOK = y1 <= 0.45;
  const isSafe   = solidOK && stressOK;

  // Update displays
  ge('disp-sigmaB').textContent = sigmaB.toString();
  ge('res-d').textContent  = fmt(d, 2);
  ge('res-Na').textContent = fmt(Na, 1);
  ge('res-k').textContent  = fmt(k, 4);
  ge('res-Hf').textContent = fmt(Hf, 2);
  ge('res-Lc').textContent = fmt(Lc, 2);
  ge('res-P1').textContent  = fmt(P1, 2);
  ge('res-tau1').textContent = fmt(tau1, 2);
  ge('sub-tau1').textContent = 'τ1/σB = ' + fmt(x1, 4);
  ge('res-Psolid').textContent = fmt(P_solid, 2);
  ge('res-tau2').textContent = fmt(tau_sol, 2);
  ge('sub-tau2').textContent = 'τ/σB = ' + fmt(y_sol, 4);
  ge('res-C').textContent = fmt(C, 2);

  // C range indicator
  const cardC = ge('card-C');
  if (C < 4) {
    cardC.className = 'mc warn'; ge('sub-C').textContent = '⚠ 小さすぎ (推奨 4〜14)';
  } else if (C > 14) {
    cardC.className = 'mc warn'; ge('sub-C').textContent = '⚠ 大きすぎ (推奨 4〜14)';
  } else {
    cardC.className = 'mc'; ge('sub-C').textContent = '推奨範囲内 (4〜14)';
  }

  // Solid height indicator
  const judgeEl = ge('res-solid-judge');
  if (!solidOK) {
    ge('card-solid').className = 'mc danger';
    judgeEl.innerHTML = '<b style="color:#A32D2D">NG</b> Lc ≥ L2';
  } else {
    ge('card-solid').className = 'mc';
    judgeEl.textContent = 'クリアランス ' + fmt(L2-Lc, 2) + ' mm';
  }

  // Badge
  const badge = ge('badge-status');
  if (isSafe)       { badge.className='badge b-gn'; badge.textContent='合格'; }
  else if(!solidOK) { badge.className='badge b-rd'; badge.textContent='密着NG'; }
  else              { badge.className='badge b-rd'; badge.textContent='応力超過'; }

  // Alerts
  let html = '';
  if (!stressOK) html += '<div class="alert al-dn"><b>応力超過</b> — τ2/σB = ' + fmt(y1,4) + ' &gt; 0.45。線径・D を見直してください。</div>';
  if (!solidOK)  html += '<div class="alert al-dn"><b>密着 NG</b> — 密着高さ Lc (' + fmt(Lc,2) + ' mm) ≥ 作動時長 L2 (' + fmt(L2,2) + ' mm)。</div>';
  if (C < 4)     html += '<div class="alert al-wn"><b>ばね指数注意</b> — C = ' + fmt(C,2) + ' が推奨下限 4 未満です。D を大きくするか線径を細くしてください。</div>';
  if (C > 14)    html += '<div class="alert al-wn"><b>ばね指数注意</b> — C = ' + fmt(C,2) + ' が推奨上限 14 超えです。</div>';
  if (isSafe)    html += '<div class="alert al-ok"><b>判定 OK</b> — τ2/σB = ' + fmt(y1,4) + ' ≤ 0.45、密着クリア、ばね指数 C = ' + fmt(C,2) + '。</div>';
  alertBox.innerHTML = html;

  // Detail table
  const tbody = ge('detail-tbody');
  tbody.innerHTML = '';
  const rows = [
    ['素線径（JIS標準）', 'd',           fmt(d,2),          'mm'],
    ['コイル中心径',      'D',           fmt(D,2),          'mm'],
    ['コイル外径',        'Do=D+d',      fmt(D+d,2),        'mm'],
    ['コイル内径',        'Di=D−d',      fmt(D-d,2),        'mm'],
    ['有効巻数',          'Na',          fmt(Na,1),         '—'],
    ['総巻数',            'Nt=Na+2',     fmt(Na+2,1),       '—'],
    ['自由高さ',          'Hf',          fmt(Hf,2),         'mm'],
    ['密着高さ',          'Lc=(Nt)·d',   fmt(Lc,2),         'mm'],
    ['ピッチ（自由）',    'p=Hf/Nt',     fmt(Hf/(Na+2),3),  'mm'],
    null,
    ['横弾性係数',        'G',           G.toLocaleString(),'MPa'],
    ['引張強さ',          'σB',          sigmaB.toString(), 'N/mm²'],
    ['ばね定数',          'k',           fmt(k,4),          'N/mm',  true],
    ['ばね指数',          'C=D/d',       fmt(C,3),          '—',     true],
    ['Wahl係数',          'K',           fmt(K,4),          '—',     true],
    null,
    ['セット長',          'L1',          fmt(L1,2),         'mm'],
    ['セット荷重',        'P1',          fmt(P1,2),         'N',     true],
    ['セット応力',        'τ1',          fmt(tau1,2),       'MPa',   true],
    ['下限応力係数',      'τ1/σB',       fmt(x1,4),         '—',     true],
    null,
    ['作動時長さ',        'L2=L1−δ',    fmt(L2,2),         'mm'],
    ['ストローク',        'δ',           fmt(stroke,2),     'mm'],
    ['作動時荷重',        'P2',          fmt(P2,2),         'N',     true],
    ['作動時応力',        'τ2',          fmt(tau2,2),       'MPa',   true],
    ['上限応力係数',      'τ2/σB',       fmt(y1,4),         '—',     true],
    ['応力比',            'R=P1/P2',     fmt(R,4),          '—',     true],
    null,
    ['密着高さ',          'Lc',          fmt(Lc,2),         'mm'],
    ['密着時荷重',        'P_solid',     fmt(P_solid,2),    'N',     true],
    ['密着時応力',        'τ_solid',     fmt(tau_sol,2),    'MPa',   true],
    ['密着応力係数',      'τ/σB',        fmt(y_sol,4),      '—',     true],
    ['密着クリアランス',  'L2−Lc',       fmt(L2-Lc,3),      'mm',    true],
  ];
  rows.forEach(row => {
    if (row === null) {
      const tr = document.createElement('tr');
      tr.innerHTML = '<td colspan="4" style="padding:2px;background:#f7f7f7;border-bottom:0.5px solid #e0e0e0"></td>';
      tbody.appendChild(tr); return;
    }
    const [name, sym, val, unit, hl] = row;
    const tr = document.createElement('tr');
    if (hl) tr.className = 'hl';
    tr.innerHTML =
      '<td>' + name + '</td>' +
      '<td style="font-style:italic;color:#888;font-size:10px">' + sym + '</td>' +
      '<td>' + val + '</td>' +
      '<td style="color:#aaa;font-size:10px">' + unit + '</td>';
    tbody.appendChild(tr);
  });

  // Draw Goodman chart
  drawGoodman(x1, y1, isSafe);

  // Store for drawing modal
  lastCalcResult = {
    matKey, d, D, Na, Hf, L1, L2,
    G, sigmaB, k, C, K, Lc,
    d1, P1, tau1, x1,
    d2: Hf-L2, P2, tau2, y1,
    P_solid, tau_solid: tau_sol,
    R, isSafe, solidOK, stressOK,
    Do: D+d, Di: D-d, Nt: Na+2,

